mapper.select:
SELECT nv.hoTen, SUM(ltd.luongCoBan * cx.tiLeThuLao) AS tongLuong, COUNT(DISTINCT cx.maChuyen) AS tongSoChuyen FROM NhanVien nv JOIN PhanCong pc ON nv.maNhanVien = pc.maNhanVien AND pc.vaiTro = #{role} JOIN ChuyenXe cx ON pc.maXe = cx.maXe AND pc.maTuyen = cx.maTuyen AND pc.maChuyen = cx.maChuyen JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen WHERE cx.tinhTrangChuyen = 'Hoàn thành' AND DATE(cx.ngayGioDen) >= #{fromDate} AND DATE(cx.ngayGioDen) < #{toDate}
AND (nv.hoTen LIKE CONCAT('%', #{keyword}, '%') OR nv.soDienThoai LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY nv.hoTen;

SELECT x.maXe, x.bienSo, COUNT(DISTINCT cx.maChuyen) AS tongSoChuyen, SUM(gv.giaVe) AS doanhThu FROM Xe x JOIN ChuyenXe cx ON x.maXe = cx.maXe JOIN Ve v ON cx.maXe = v.maXe AND cx.maTuyen = v.maTuyen AND cx.maChuyen = v.maChuyen JOIN GiaVe gv ON cx.maTuyen = gv.maTuyen AND cx.maMua = gv.maMua AND cx.maGiaVe = gv.maGiaVe WHERE x.tinhTrang = 'Đang hoạt động' AND cx.tinhTrangChuyen = 'Hoàn thành' AND DATE(cx.ngayGioDen) >= #{fromDate} AND DATE(cx.ngayGioDen) < #{toDate} AND cx.ngayGioKhoiHanh >= gv.ngayBatDau AND (gv.ngayKetThuc IS NULL OR cx.ngayGioKhoiHanh <= gv.ngayKetThuc)
AND (x.maXe LIKE CONCAT('%', #{keyword}, '%') OR x.bienSo LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY x.maXe, x.bienSo;
